读下列一段代码，写出实参调用func(list, 0, 4)的输出结果。(6分)
int list[4] = { 1,2,3,4 };
void Swap(int& a, int& b) { int t = a; a = b; b = t; }
void func(int a[], int k, int n) {
int i, state;
if (k == n - 1) {
state = 0;
for (i = 0; i < n; i++)
if (a[i] % 2 != (i + 1) % 2) { state = 1; break; };
if (!state) {
for (i = 0; i < n; i++) printf("%d", list[i]);
printf("\n");
};
return;
}
for (i = k; i < n; i++) {
Swap(a[k], a[i]);
func(a, k + 1, n);
Swap(a[k], a[i]);
}
}

